// C# — Singly Linked List: Create, Search, Insert, Remove

public class Node
{
    public int Data { get; set; }
    public Node? Next { get; set; }
    public Node(int data) { Data = data; Next = null; }
}

public class SinglyLinkedList
{
    private Node? head;

    // Create — append a new node at the tail
    public void Create(int data)
    {
        var newNode = new Node(data);
        if (head is null)
        {
            head = newNode;
            return;
        }
        var current = head;
        while (current.Next is not null)
            current = current.Next;
        current.Next = newNode;
    }

    // Search — find value, return index or -1
    public int Search(int target)
    {
        var current = head;
        int index = 0;
        while (current is not null)
        {
            if (current.Data == target) return index;
            current = current.Next;
            index++;
        }
        return -1;
    }

    // Insert — add a node at a specific position (0 = head)
    public void Insert(int data, int position)
    {
        var newNode = new Node(data);
        if (position == 0)
        {
            newNode.Next = head;
            head = newNode;
            return;
        }
        var current = head;
        for (int i = 0; i < position - 1 && current is not null; i++)
            current = current.Next;
        if (current is null) throw new IndexOutOfRangeException("Position out of range.");
        newNode.Next = current.Next;
        current.Next = newNode;
    }

    // Remove — delete node at a specific position
    public void Remove(int position)
    {
        if (head is null) throw new InvalidOperationException("List is empty.");
        if (position == 0)
        {
            head = head.Next;
            return;
        }
        var current = head;
        for (int i = 0; i < position - 1 && current.Next is not null; i++)
            current = current.Next;
        if (current.Next is null) throw new IndexOutOfRangeException("Position out of range.");
        current.Next = current.Next.Next;
    }
}

