};

class SinglyLinkedList {
    Node* head = nullptr;
public:
    // Create — append at tail
    void create(int data) {
        Node* newNode = new Node(data);
        if (!head) { head = newNode; return; }
        Node* current = head;
        while (current->next) current = current->next;
        current->next = newNode;
    }

    // Search — return index or -1
    int search(int target) {
        Node* current = head;
        int index = 0;
        while (current) {
            if (current->data == target) return index;
            current = current->next;
            index++;
        }
        return -1;
    }

    // Insert at position
    void insert(int data, int position) {
        Node* newNode = new Node(data);
        if (position == 0) {
            newNode->next = head;
            head = newNode;
            return;
        }
        Node* current = head;
        for (int i = 0; i < position - 1 && current; i++)
            current = current->next;
        if (!current) { cout << "Position out of range." << endl; return; }
        newNode->next = current->next;
        current->next = newNode;
    }

    // Remove at position
    void remove(int position) {
        if (!head) { cout << "List is empty." << endl; return; }
        if (position == 0) {
            Node* temp = head;
            head = head->next;
            delete temp;
            return;
        }
        Node* current = head;
        for (int i = 0; i < position - 1 && current->next; i++)
            current = current->next;
        if (!current->next) { cout << "Position out of range." << endl; return; }
        Node* temp = current->next;
        current->next = temp->next;
        delete temp;
    }
};

// Java — Singly Linked List: Create, Search, Insert, Remove

class Node {
    int data;
    Node next;
    Node(int data) { this.data = data; this.next = null; }
}

public class SinglyLinkedList {
    private Node head;

    // Create — append at tail
    public void create(int data) {
        Node newNode = new Node(data);
        if (head == null) { head = newNode; return; }
        Node current = head;
        while (current.next != null) current = current.next;
        current.next = newNode;
    }

    // Search — return index or -1
    public int search(int target) {
        Node current = head;
        int index = 0;
        while (current != null) {
            if (current.data == target) return index;
            current = current.next;
            index++;
        }
        return -1;
    }

    // Insert at position
    public void insert(int data, int position) {
        Node newNode = new Node(data);
        if (position == 0) {
            newNode.next = head;
            head = newNode;
            return;
        }
        Node current = head;
        for (int i = 0; i < position - 1 && current != null; i++)
            current = current.next;
        if (current == null) throw new IndexOutOfBoundsException("Position out of range.");
        newNode.next = current.next;
        current.next = newNode;
    }

    // Remove at position
    public void remove(int position) {
        if (head == null) throw new IllegalStateException("List is empty.");
        if (position == 0) { head = head.next; return; }
        Node current = head;
        for (int i = 0; i < position - 1 && current.next != null; i++)
            current = current.next;
        if (current.next == null) throw new IndexOutOfBoundsException("Position out of range.");
        current.next = current.next.next;
    }
}

