class SinglyLinkedList {
    constructor() {
        this.head = null;
    }

    // Create — append at tail
    create(data) {
        const newNode = new Node(data);
        if (!this.head) { this.head = newNode; return; }
        let current = this.head;
        while (current.next) current = current.next;
        current.next = newNode;
    }

    // Search — return index or -1
    search(target) {
        let current = this.head;
        let index = 0;
        while (current) {
            if (current.data === target) return index;
            current = current.next;
            index++;
        }
        return -1;
    }

    // Insert at position
    insert(data, position) {
        const newNode = new Node(data);
        if (position === 0) {
            newNode.next = this.head;
            this.head = newNode;
            return;
        }
        let current = this.head;
        for (let i = 0; i < position - 1 && current; i++)
            current = current.next;
        if (!current) throw new Error('Position out of range.');
        newNode.next = current.next;
        current.next = newNode;
    }

    // Remove at position
    remove(position) {
        if (!this.head) throw new Error('List is empty.');
        if (position === 0) { this.head = this.head.next; return; }
        let current = this.head;
        for (let i = 0; i < position - 1 && current.next; i++)
            current = current.next;
        if (!current.next) throw new Error('Position out of range.');
        current.next = current.next.next;
    }
}
